routeWithLocation.code:
type RouteLocationKind = "normal" | "informated";

function createRouteWithLocation(kind: RouteLocationKind, state: "default" | "muted" | "completed") {
  const content = document.createElement("div");
  content.className = `MapRoutePreview MapRoutePreview--routeWith${kind}Location MapRoutePreview--${state}`;
  content.innerHTML = `
    <span class="MapRouteComposite">
      <span class="MapRouteComposite__line"><span class="MapRouteComposite__segment--active" /></span>
      <span class="MapRouteComposite__point MapRouteComposite__point--start" />
      <span class="MapRouteComposite__point MapRouteComposite__point--end" />
    </span>
  `;
  return content;
}

